import React, { useState, useEffect } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const [positions, setPositions] = useState([]);
  const [containerSize, setContainerSize] = useState({ width: 0, height: 0 });

  const allSkills = [
    { name: 'React', icon: '⚛️', desc: 'UI Library' },
    { name: 'Next.js', icon: '▲', desc: 'React Framework' },
    { name: 'TypeScript', icon: '📘', desc: 'Typed JS' },
    { name: 'JavaScript', icon: '⚡', desc: 'Programming' },
    { name: 'HTML5', icon: '🌐', desc: 'Markup' },
    { name: 'CSS3', icon: '🎨', desc: 'Styling' },
    { name: 'Tailwind CSS', icon: '💨', desc: 'Utility CSS' },
    { name: 'Redux', icon: '🔄', desc: 'State Mgmt' },
    { name: 'Framer Motion', icon: '🎬', desc: 'Animations' },
    { name: 'Node.js', icon: '🟢', desc: 'Runtime' },
    { name: 'Express.js', icon: '🚀', desc: 'Framework' },
    { name: 'MongoDB', icon: '🍃', desc: 'NoSQL DB' },
    { name: 'JWT', icon: '🔐', desc: 'Auth' },
    { name: 'REST API', icon: '🔗', desc: 'APIs' },
    { name: 'Socket.io', icon: '📡', desc: 'Real-time' },
    { name: 'Mongoose', icon: '📦', desc: 'ODM' },
    { name: 'Cloudinary', icon: '☁️', desc: 'Cloud Storage' }
  ];

  const skillSize = 65;

  // Check if two positions overlap
  const isOverlapping = (pos1, pos2, minDistance) => {
    const dx = pos1.x - pos2.x;
    const dy = pos1.y - pos2.y;
    return (dx * dx + dy * dy) < (minDistance * minDistance);
  };

  // Generate non-overlapping positions
  const generateNonOverlappingPositions = (count, containerW, containerH) => {
    const minDistance = 85;
    const positions = [];
    const maxAttempts = 1000;
    const margin = 5;

    for (let i = 0; i < count; i++) {
      let attempts = 0;
      let pos;
      let found = false;

      while (!found && attempts < maxAttempts) {
        pos = {
          x: margin + Math.random() * (containerW - margin * 2),
          y: margin + Math.random() * (containerH - margin * 2),
          targetX: margin + Math.random() * (containerW - margin * 2),
          targetY: margin + Math.random() * (containerH - margin * 2),
          duration: 6 + Math.random() * 6,
          delay: Math.random() * 2,
          size: 55 + Math.random() * 25
        };

        let overlapping = false;
        for (const existing of positions) {
          if (isOverlapping(pos, existing, minDistance)) {
            overlapping = true;
            break;
          }
        }

        if (!overlapping) {
          found = true;
        }
        attempts++;
      }

      if (found) {
        positions.push(pos);
      } else {
        // If can't find position, place randomly anyway
        positions.push({
          x: margin + Math.random() * (containerW - margin * 2),
          y: margin + Math.random() * (containerH - margin * 2),
          targetX: margin + Math.random() * (containerW - margin * 2),
          targetY: margin + Math.random() * (containerH - margin * 2),
          duration: 6 + Math.random() * 6,
          delay: Math.random() * 2,
          size: 55 + Math.random() * 25
        });
      }
    }

    return positions;
  };

  // Initialize and update positions
  useEffect(() => {
    const updatePositions = () => {
      const container = document.getElementById('skills-container');
      if (container) {
        const rect = container.getBoundingClientRect();
        const w = rect.width - 40;
        const h = rect.height - 40;
        setContainerSize({ width: w, height: h });

        const newPositions = generateNonOverlappingPositions(allSkills.length, w, h);
        setPositions(newPositions);
      }
    };

    updatePositions();

    // Update every 5 seconds
    const interval = setInterval(() => {
      setPositions(prev => {
        const container = document.getElementById('skills-container');
        if (container) {
          const rect = container.getBoundingClientRect();
          const w = rect.width - 40;
          const h = rect.height - 40;

          return prev.map((pos, index) => {
            const newTarget = {
              x: 5 + Math.random() * (w - 10),
              y: 5 + Math.random() * (h - 10)
            };

            // Check if new target overlaps with others
            let attempts = 0;
            let valid = false;
            let targetX = newTarget.x;
            let targetY = newTarget.y;

            while (!valid && attempts < 50) {
              valid = true;
              for (let i = 0; i < prev.length; i++) {
                if (i !== index) {
                  const other = prev[i];
                  const dx = targetX - other.x;
                  const dy = targetY - other.y;
                  if ((dx * dx + dy * dy) < (85 * 85)) {
                    valid = false;
                    targetX = 5 + Math.random() * (w - 10);
                    targetY = 5 + Math.random() * (h - 10);
                    break;
                  }
                }
              }
              attempts++;
            }

            return {
              ...pos,
              targetX: targetX,
              targetY: targetY,
              duration: 5 + Math.random() * 5
            };
          });
        }
        return prev;
      });
    }, 5000);

    // Update on resize
    window.addEventListener('resize', updatePositions);

    return () => {
      clearInterval(interval);
      window.removeEventListener('resize', updatePositions);
    };
  }, []);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          id="skills-container"
          className="relative min-h-[650px] w-full"
        >
          {/* Background Glow */}
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-[500px] h-[500px] rounded-full bg-purple-500/5 blur-3xl"></div>
          </div>

          {allSkills.map((skill, index) => {
            const pos = positions[index] || { 
              x: 50, 
              y: 50, 
              targetX: 50, 
              targetY: 50, 
              duration: 5, 
              delay: 0, 
              size: 60 
            };

            return (
              <div
                key={index}
                onMouseEnter={() => setHoveredSkill(skill.name)}
                onMouseLeave={() => setHoveredSkill(null)}
                className="absolute cursor-pointer transition-all ease-in-out"
                style={{
                  left: `${pos.x}%`,
                  top: `${pos.y}%`,
                  transform: 'translate(-50%, -50%)',
                  transitionProperty: 'left, top',
                  transitionDuration: `${pos.duration}s`,
                  transitionDelay: `${pos.delay}s`,
                  zIndex: hoveredSkill === skill.name ? 50 : 10,
                  opacity: hoveredSkill === skill.name ? 1 : 0.7
                }}
              >
                <div 
                  className="flex flex-col items-center justify-center rounded-full backdrop-blur-sm transition-all duration-500"
                  style={{
                    width: hoveredSkill === skill.name ? `${pos.size + 30}px` : `${pos.size}px`,
                    height: hoveredSkill === skill.name ? `${pos.size + 30}px` : `${pos.size}px`,
                    boxShadow: hoveredSkill === skill.name ? '0 0 50px rgba(139,92,246,0.3)' : 'none',
                    transform: hoveredSkill === skill.name ? 'scale(1.2)' : 'scale(1)',
                    background: hoveredSkill === skill.name 
                      ? 'rgba(26,31,46,0.9)' 
                      : 'rgba(26,31,46,0.3)',
                    border: hoveredSkill === skill.name 
                      ? '1px solid rgba(139,92,246,0.5)' 
                      : '1px solid rgba(255,255,255,0.05)'
                  }}
                >
                  <span 
                    className="transition-all duration-500"
                    style={{ 
                      fontSize: hoveredSkill === skill.name ? '26px' : '18px',
                      filter: hoveredSkill === skill.name ? 'brightness(1.3)' : 'brightness(0.7)'
                    }}
                  >
                    {skill.icon}
                  </span>

                  {hoveredSkill === skill.name && (
                    <>
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                      <span className="text-[7px] text-purple-300 animate-fadeIn">
                        {skill.desc}
                      </span>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">20+</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
